   330→        costConsideration: 'costThresholdNotMet',
   331→      };
   332→    }
   333→  }
   334→
   335→  // Default case (shouldn't reach here with proper threshold ordering: low < aiRequired < high)
   336→  return {
   337→    routeToAi: false,
   338→    routingReason: `Unclear confidence assessment (score: ${primaryScore}) - defaulting to rule-based results`,
   339→    confidenceAssessment: 'unclear',
