   341→  };
   342→}
   343→
   344→/**
   345→ * Check if there are close competing categories that AI could help disambiguate
   346→ */
   347→function checkCloseCompetitors(
   348→  candidateScores: Record<string, CandidateScore>,
   349→  primaryScore: number,
   350→  competitorGap: number = 3
   351→): boolean {
   352→  const competitors = Object.entries(candidateScores)
   353→    .map(([categoryCode, scoreData]) => ({
   354→      category: categoryCode,
   355→      score: scoreData.score || 0,
   356→    }))
