   388→        lowConfidenceThreshold: thresholds.lowConfidenceThreshold,
   389→        primaryScore: primaryLabel?.confidence || 0,
   390→        thresholdMet: primaryLabel?.confidence >= thresholds.aiRequiredThreshold ? 'aiRequired' : 'belowThreshold',
